  ('pukao-10ced7e2-moex-00289', 'pukao-10ced7e2', 'pukao-10ced7e2-moex-112-d1a761c9', 'sub-pukao-10ced7e2-03', NULL, 'single_choice', '下列何者非屬行政事實行為？', '["拆除違章建築", "興建道路", "公告某市立公園開放供民眾使用", "依集會遊行法，對不服解散命令之遊行者強制驅離"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:25+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "411", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "人事行政"}'::jsonb, NULL),
  ('pukao-10ced7e2-moex-00290', 'pukao-10ced7e2', 'pukao-10ced7e2-moex-112-d1a761c9', 'sub-pukao-10ced7e2-03', NULL, 'single_choice', '裁罰所適用之法規中「公告」內容之變更，應如何適用行政罰法之規定？', '["係屬事實上之變更，並非處罰法律有所變更，故無從新從輕原則適用", "係屬事實及處罰法律皆有所變更，故有從新從輕原則適用", "係屬處罰法律有所變更，故有從新從輕原則適用", "係屬事實及處罰法律皆未有變更，故無從新從輕原則適用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:25+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "411", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "人事行政"}'::jsonb, NULL),
  ('pukao-10ced7e2-moex-00291', 'pukao-10ced7e2', 'pukao-10ced7e2-moex-112-d1a761c9', 'sub-pukao-10ced7e2-03', NULL, 'single_choice', '行政罰法有關單一行為及數行為之處罰規定，下列敘述何者錯誤？', '["數行為違反同一或不同行政法上義務之規定者，應為整體性評價處罰之", "一行為違反數個行政法上義務規定而應處罰鍰者，依法定罰鍰額最高之規定裁處", "一行為違反社會秩序維護法及其他行政法上義務規定而應受處罰，如已裁處拘留者，不再受罰鍰之處罰", "一行為同時觸犯刑事法律及違反行政法上義務規定者，原則上依刑事法律處罰之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:25+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "411", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "人事行政"}'::jsonb, NULL),
  ('pukao-10ced7e2-moex-00292', 'pukao-10ced7e2', 'pukao-10ced7e2-moex-112-d1a761c9', 'sub-pukao-10ced7e2-03', NULL, 'single_choice', '下列何者非屬行政罰法規定原則上不予處罰之情形？', '["行為時因精神障礙，致欠缺依其辨識而行為之能力者", "行為人不知其行為違反行政法上義務", "未滿14歲人之行為", "緊急避難"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:25+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "411", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "人事行政"}'::jsonb, NULL),
  ('pukao-10ced7e2-moex-00293', 'pukao-10ced7e2', 'pukao-10ced7e2-moex-112-d1a761c9', 'sub-pukao-10ced7e2-03', NULL, 'single_choice', '下列何者非屬行政罰法規定之處罰種類？', '["拘留", "沒入", "公布照片", "輔導教育"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:25+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "411", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "人事行政"}'::jsonb, NULL),
  ('pukao-10ced7e2-moex-00294', 'pukao-10ced7e2', 'pukao-10ced7e2-moex-112-d1a761c9', 'sub-pukao-10ced7e2-03', NULL, 'single_choice', '關於即時強制，下列敘述何者錯誤？', '["即時強制扣留之物，以軍器、凶器及其他危險物為限", "即時強制以人民有違反行政法上義務為前提", "即時強制方法包括對於人之管束", "行政機關為阻止犯罪，而有即時處置之必要時，得為即時強制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:25+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "411", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "人事行政"}'::jsonb, NULL),
  ('pukao-10ced7e2-moex-00295', 'pukao-10ced7e2', 'pukao-10ced7e2-moex-112-d1a761c9', 'sub-pukao-10ced7e2-03', NULL, 'single_choice', '關於怠金，下列敘述何者錯誤？', '["適用於義務人不履行義務，而該義務不能由他人代為履行之強制執行方法", "得與罰金同時併科", "可連續科以怠金，但應注意比例原則", "逾期未繳納之怠金，得移送行政執行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:25+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "411", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "人事行政"}'::jsonb, NULL),
