  ('pukao-10ced7e2-moex-00297', 'pukao-10ced7e2', 'pukao-10ced7e2-moex-112-d1a761c9', 'sub-pukao-10ced7e2-03', NULL, 'single_choice', '依政府資訊公開法規定，下列敘述何者錯誤？', '["受理申請提供政府資訊之行政機關，應於受理之日起15日內，為准駁之決定", "受理申請更正政府資訊內容之行政機關，應於受理之日起30日內，為准駁之決定", "申請提供之政府資訊涉及特定個人之權益者，得以書面通知該特定人，於10日內表達意見", "申請提供之政府資訊已在該政府機關官方網頁上公告者，得以告知查詢方式替代提供"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:25+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "411", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "人事行政"}'::jsonb, NULL),
